import{_ as t,c as o,o as r,a3 as n}from"./chunks/framework.CTM16EAR.js";const u=JSON.parse('{"title":"桌面客户端说明","description":"安装包下载、系统要求与安装排错。账号、同步与 JSON 见《账号与数据》；浏览器端见《PWA网页应用说明》。","frontmatter":{"title":"桌面客户端说明","description":"安装包下载、系统要求与安装排错。账号、同步与 JSON 见《账号与数据》；浏览器端见《PWA网页应用说明》。"},"headers":[],"relativePath":"guide/intro/desktop-install.md","filePath":"guide/intro/desktop-install.md","lastUpdated":1778035726000}'),e={name:"guide/intro/desktop-install.md"};function l(s,a,i,d,c,h){return r(),o("div",null,a[0]||(a[0]=[n('<h1 id="桌面客户端说明" tabindex="-1">桌面客户端说明 <a class="header-anchor" href="#桌面客户端说明" aria-label="Permalink to &quot;桌面客户端说明&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">与 PWA / 网页 的分工</p><ul><li><strong>桌面客户端</strong>：<code>.msi</code> / <code>.dmg</code> <strong>独立安装</strong>；本机 <strong>单一本地库</strong>；<strong>全量 JSON 导出</strong> 仅桌面开放，详见 <a href="./account-and-data.html">账号与数据</a>。置顶与系统集成以桌面端为准。</li><li><strong>不打算装桌面、用浏览器即可</strong>：安装方式、标签页与 PWA 存储差异、白屏排查等见 <a href="./pwa-install.html">PWA渐进式网页应用说明</a>。</li></ul></div><h2 id="当前版本" tabindex="-1">当前版本 <a class="header-anchor" href="#当前版本" aria-label="Permalink to &quot;当前版本&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">最新发布</p><p><strong>版本 v0.6.4</strong> · 2026 年 4 月 2 日</p></div><ul><li><a href="./../../dev-log/CHANGELOG.html">完整更新日志</a></li></ul><h2 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows&quot;">​</a></h2><h3 id="系统要求" tabindex="-1">系统要求 <a class="header-anchor" href="#系统要求" aria-label="Permalink to &quot;系统要求&quot;">​</a></h3><ul><li>Windows 10 或更高版本</li><li>64 位系统</li></ul><h3 id="下载与安装" tabindex="-1">下载与安装 <a class="header-anchor" href="#下载与安装" aria-label="Permalink to &quot;下载与安装&quot;">​</a></h3><p>使用官方发布的 <strong><a href="https://github.com/Xeonilian/pomotention/releases/download/v0.6.4/Pomotention_0.6.4_x64_en-US.msi" target="_blank" rel="noreferrer">v0.6.4 Windows 安装包（.msi）</a></strong>。下载完成后双击运行安装程序，按向导完成安装；安装结束后从 <strong>开始菜单</strong> 启动应用。</p><div class="warning custom-block"><p class="custom-block-title">安全提示</p><p>若浏览器或系统提示「已保护你的电脑」「阻止下载」等，可在 <strong>更多信息</strong> → <strong>仍要运行</strong>，或对被拦截的下载选择 <strong>保留</strong>。</p></div><h2 id="macos" tabindex="-1">macOS <a class="header-anchor" href="#macos" aria-label="Permalink to &quot;macOS&quot;">​</a></h2><h3 id="系统要求-1" tabindex="-1">系统要求 <a class="header-anchor" href="#系统要求-1" aria-label="Permalink to &quot;系统要求&quot;">​</a></h3><ul><li>macOS 13.0 (Ventura) 或更高版本</li><li>webkit 支持不完全导致 macOS 12.0 可安装，部分渲染失败</li></ul><h3 id="下载与安装-1" tabindex="-1">下载与安装 <a class="header-anchor" href="#下载与安装-1" aria-label="Permalink to &quot;下载与安装&quot;">​</a></h3><ul><li>使用官方发布的 <strong><a href="https://github.com/Xeonilian/pomotention/releases/download/v0.6.4/Pomotention_0.6.4_x64.dmg" target="_blank" rel="noreferrer">v0.6.4 macOS 安装包（.dmg）</a></strong>。</li><li>下载完成后双击打开磁盘映像，将应用拖入 <strong>应用程序</strong> 文件夹，再从 Launchpad 或 <strong>应用程序</strong> 中启动。</li></ul><div class="warning custom-block"><p class="custom-block-title">安全提示</p><p>首次运行时若被拦截，在 <strong>系统设置 → 隐私与安全性</strong>（或旧版系统中的 <strong>系统偏好设置 → 安全性与隐私</strong>）中按提示 <strong>仍要打开</strong> / 允许运行。</p></div><h2 id="自动更新" tabindex="-1">自动更新 <a class="header-anchor" href="#自动更新" aria-label="Permalink to &quot;自动更新&quot;">​</a></h2><ul><li>软件提供自动更新检测；由于网络原因可能下载失败。</li><li>在 <strong>帮助页</strong> 可查看本地与云端版本对比，并打开或关闭自动更新。</li></ul><h2 id="遇到问题" tabindex="-1">遇到问题 <a class="header-anchor" href="#遇到问题" aria-label="Permalink to &quot;遇到问题&quot;">​</a></h2><h3 id="下载与安装-2" tabindex="-1">下载与安装 <a class="header-anchor" href="#下载与安装-2" aria-label="Permalink to &quot;下载与安装&quot;">​</a></h3><ol><li><strong>下载失败</strong>：先检查网络连接，或改用下载工具。若怀疑同步或首次启动拉取失败，可稍后再试（参见更新日志中初始化顺序与同步相关修复）。<code>设置页</code>里可对当前网络环境做连通性测试。</li><li><strong>安装报错</strong>：确认系统版本符合要求；<strong>Windows 7</strong> 暂不支持。</li><li><strong>安装中断</strong>：在 <strong>Windows</strong> 上可从任务管理器结束相关进程后重试安装。</li></ol><h3 id="白屏、界面长时间不加载" tabindex="-1">白屏、界面长时间不加载 <a class="header-anchor" href="#白屏、界面长时间不加载" aria-label="Permalink to &quot;白屏、界面长时间不加载&quot;">​</a></h3><p>桌面端是 <strong>独立应用</strong>（不是浏览器标签页），排错与 <a href="./pwa-install.html#pwa-blank-screen">PWA 里的「强制刷新页面」</a> <strong>不是同一套操作</strong>。</p><ol><li><strong>先完全退出应用再重新打开</strong>；仍异常时到 <code>设置页</code> 做网络 / 环境诊断（与 PWA 文档中的「环境诊断」为同一套能力时，说明一致）。</li><li><strong>需要重置本地数据时</strong>：在 <code>设置页</code> 使用清除本地数据等功能。<strong>清除前若数据未上云</strong>，请先按 <a href="./account-and-data.html#json-export-desktop">账号与数据 · JSON 全量导出</a> 导出 JSON，避免丢失。</li><li>若你同时在用 <strong>浏览器里的 PWA 或网页版</strong>，白屏、缓存类问题以 <a href="./pwa-install.html#pwa-blank-screen">PWA渐进式网页应用说明 · 白屏或加载不出</a> 为准；桌面与浏览器的数据库相互独立，除非通过登录同步或 JSON 迁移。</li></ol><p>注册、登录、同步、JSON 导入导出（各端差异见对照表）见 <strong><a href="./account-and-data.html">账号与数据</a></strong>。</p>',26)]))}const m=t(e,[["render",l]]);export{u as __pageData,m as default};
